{
  description = "Test examples for all headless browser libraries";

  inputs = {
    nixpkgs.url = "github:NixOS/nixpkgs/nixos-unstable";
    rust-overlay.url = "github:oxalica/rust-overlay";
    flake-utils.url = "github:numtide/flake-utils";
  };

  outputs = { self, nixpkgs, rust-overlay, flake-utils }:
    flake-utils.lib.eachDefaultSystem (system:
      let
        overlays = [ (import rust-overlay) ];
        pkgs = import nixpkgs {
          inherit system overlays;
        };
        rustToolchain = pkgs.rust-bin.stable.latest.default.override {
          extensions = [ "rust-src" "rust-analyzer" ];
        };
      in
      {
        devShells.default = pkgs.mkShell {
          buildInputs = with pkgs; [
            rustToolchain
            pkg-config
            openssl
            chromium
            geckodriver
            firefox
            chromedriver
          ];

          shellHook = ''
            echo "🦀 Headless Browser Test Examples Environment"
            echo "================================================"
            echo "Chromium:     ${pkgs.chromium}/bin/chromium"
            echo "Geckodriver:  ${pkgs.geckodriver}/bin/geckodriver"
            echo "Chromedriver: ${pkgs.chromedriver}/bin/chromedriver"
            echo ""
            echo "Available tests:"
            echo "  - cargo run --bin test-rust-headless-chrome"
            echo "  - cargo run --bin test-fantoccini (requires WebDriver server)"
            echo "  - cargo run --bin test-chromiumoxide"
            echo ""
            export CHROME_BIN="${pkgs.chromium}/bin/chromium"
            export CHROME="${pkgs.chromium}/bin/chromium"
            export GECKODRIVER="${pkgs.geckodriver}/bin/geckodriver"
            export CHROMEDRIVER="${pkgs.chromedriver}/bin/chromedriver"
          '';
        };
      }
    );
}

